// CSV
const csvText = $('Fetch Debt CSV').first().json.data || '';

// Комментарии
const comments = {};
$('Read Comments').all().forEach(item => {
  const r = item.json;
  if (r.client_name) comments[r.client_name] = { comment: r.comment || '', login: r.login || '' };
});

// Парсер CSV
function splitLine(line) {
  const res = []; let cur = '', inQ = false;
  for (let i = 0; i < line.length; i++) {
    const c = line[i];
    if (c === '"') { if (inQ && line[i+1]==='"') { cur+='"'; i++; } else inQ=!inQ; }
    else if (c === ',' && !inQ) { res.push(cur); cur=''; }
    else cur += c;
  }
  res.push(cur); return res;
}

const lines = csvText.trim().split(/\r?\n/);
const hdr = splitLine(lines[0] || '');
const idxDate   = hdr.indexOf('as_of_date');
const idxClient = hdr.indexOf('client_name');
const idxOver   = hdr.indexOf('overdue_amount');
const idxDays   = hdr.indexOf('days_overdue');
const idxCredit = hdr.indexOf('credit_days_from_registry');

const allDates = lines.slice(1).map(l => splitLine(l)[idxDate]).filter(Boolean).sort();
const snap = allDates[allDates.length - 1] || '';

const today = new Date().toLocaleDateString('ru-RU', { day:'2-digit', month:'2-digit', year:'numeric' });

// Группировка просроченных
const clientMap = {};
lines.slice(1).forEach(line => {
  const cells = splitLine(line);
  if (!cells.length || cells[idxDate] !== snap) return;
  const overAmt = parseFloat((cells[idxOver]||'0').replace(',','.')) || 0;
  if (overAmt <= 0) return;
  const client = (cells[idxClient] || '').trim();
  if (!client) return;
  if (!clientMap[client]) clientMap[client] = { overdue: 0, maxDays: 0 };
  clientMap[client].overdue += overAmt;
  const days = parseFloat((cells[idxDays]||'0').replace(',','.')) || 0;
  const credit = parseFloat((cells[idxCredit]||'0').replace(',','.')) || 0;
  const actual = Math.max(0, days - credit);
  if (actual > clientMap[client].maxDays) clientMap[client].maxDays = actual;
});

// Сортировка по убыванию просрочки
const reportRows = Object.entries(clientMap)
  .sort((a, b) => b[1].overdue - a[1].overdue)
  .map(([client, info]) => {
    const cm = comments[client] || { comment: '', login: '' };
    return {
      report_date:    today,
      client_name:    client,
      overdue_amount: info.overdue,
      overdue_fmt:    info.overdue.toLocaleString('ru-RU', { minimumFractionDigits: 2, maximumFractionDigits: 2 }) + ' ₽',
      days_overdue:   info.maxDays,
      comment:        cm.comment,
      login:          cm.login
    };
  });

const historyRows = reportRows.filter(r => r.comment).map(r => ({
  date:        today,
  client_name: r.client_name,
  comment:     r.comment,
  login:       r.login
}));

// HTML письмо
const rowsHtml = reportRows.map((r, i) => {
  const bg = i % 2 === 0 ? '#ffffff' : '#f8f9fa';
  const amtColor = '#c0152f';
  const comment = r.comment
    ? `<span style="color:#1a2a4a">${r.comment}</span><br><span style="font-size:11px;color:#9ca3af">${r.login}</span>`
    : '<span style="color:#9ca3af;font-style:italic">—</span>';
  return `<tr style="background:${bg}">
    <td style="padding:10px 14px;border-bottom:1px solid #e5e7eb;font-size:13px;color:#1a2a4a">${r.client_name}</td>
    <td style="padding:10px 14px;border-bottom:1px solid #e5e7eb;font-size:13px;font-weight:700;color:${amtColor};white-space:nowrap;text-align:right">${r.overdue_fmt}</td>
    <td style="padding:10px 14px;border-bottom:1px solid #e5e7eb;font-size:13px">${comment}</td>
  </tr>`;
}).join('');

const emailHtml = `
<!DOCTYPE html><html><body style="margin:0;padding:0;background:#f7f8fa;font-family:Inter,Arial,sans-serif">
<div style="max-width:800px;margin:24px auto;background:#fff;border-radius:12px;overflow:hidden;box-shadow:0 2px 8px rgba(0,0,0,.08)">
  <div style="background:#1a2a4a;padding:20px 28px">
    <div style="color:#fff;font-size:18px;font-weight:700">Отчёт по просроченной задолженности</div>
    <div style="color:rgba(255,255,255,.7);font-size:13px;margin-top:4px">ООО «ТК «Велес» — ${today}</div>
  </div>
  <div style="padding:20px 28px">
    <table width="100%" cellpadding="0" cellspacing="0" style="border-collapse:collapse;border:1px solid #e5e7eb;border-radius:8px;overflow:hidden">
      <thead>
        <tr style="background:#1a2a4a">
          <th style="padding:10px 14px;text-align:left;color:#fff;font-size:11px;font-weight:600;letter-spacing:.05em;white-space:nowrap">КЛИЕНТ</th>
          <th style="padding:10px 14px;text-align:right;color:#fff;font-size:11px;font-weight:600;letter-spacing:.05em;white-space:nowrap">ПРОСРОЧЕННЫЙ ДОЛГ</th>
          <th style="padding:10px 14px;text-align:left;color:#fff;font-size:11px;font-weight:600;letter-spacing:.05em">КОММЕНТАРИЙ МЕНЕДЖЕРА</th>
        </tr>
      </thead>
      <tbody>${rowsHtml}</tbody>
    </table>
    <div style="margin-top:16px;font-size:12px;color:#6b7280">Клиентов с просрочкой: ${reportRows.length} &nbsp;|&nbsp; Данные на ${snap || today}</div>
  </div>
</div>
</body></html>`;

return [{ json: { today, snap, reportRows, historyRows, emailHtml, count: reportRows.length } }];

const rows = $('Build All').first().json.reportRows || [];
if (!rows.length) return [{ json: { _empty: true } }];
return rows.map(r => ({ json: {
  report_date:    r.report_date,
  client_name:    r.client_name,
  overdue_amount: r.overdue_amount.toFixed(2),
  days_overdue:   r.days_overdue,
  comment:        r.comment,
  login:          r.login
}}));

const rows = $('Build All').first().json.historyRows || [];
if (!rows.length) return [{ json: { _empty: true } }];
return rows.map(r => ({ json: r }));
